final:
module RefModule(  
    input wire clk,  
    input wire S,  
    input wire R,  
    output reg Q  
);  
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
    if (S)  
        Q <= 1;  
    else if (R)  
        Q <= 0;  
end  
endmodule
